+#[test]
+fn pthread_thread_fixture_executes_with_host_parity_via_harness_matrix() {
+    let fixture = load_fixture("pthread_thread");
+
+    for case in &fixture.cases {
+        let expected_output = case
+            .expected_output
+            .as_ref()
+            .cloned()
+            .unwrap_or_else(|| panic!("case {} missing expected_output", case.name));
+        let modes: &[&str] = if case.mode.eq_ignore_ascii_case("both") {
+            &["strict", "hardened"]
+        } else {
+            &[case.mode.as_str()]
+        };
+
+        for mode in modes {
+            let result = execute_case_via_harness(&case.function, &case.inputs, mode)
+                .unwrap_or_else(|err| {
+                    panic!(
+                        "pthread_thread case {} ({mode}) failed to execute via harness: {err}",
+                        case.name
+                    )
+                });
+            assert!(
+                result.host_parity,
+                "pthread_thread case {} ({mode}) lost host parity via harness: host_output={}, impl_output={}",
+                case.name, result.host_output, result.impl_output
+            );
+            assert_eq!(
+                result.impl_output, expected_output,
+                "pthread_thread case {} ({mode}) mismatched fixture output via harness",
+                case.name
+            );
+        }
+    }
+}
